func localHasPackage(path string) bool {
    _, ok := localPackagePaths[path]
    return ok
}

func localPackageFunctionNames(path string) []string {
    if names, ok := localPackageFunctionNameMap[path]; ok {
        return names
    }
    return []string{}
}

func localPackageMemberNames(path string) []string {
    if names, ok := localPackageMemberNameMap[path]; ok {
        return names
    }
    return []string{}
}

func localPackageMemberType(path string, name string) string {
    if names, ok := localPackageMemberTypes[path]; ok {
        if typ, ok := names[name]; ok {
            return typ
        }
    }
    return ""
}

func localPackageFuncPrototype(path string, name string) base.Option[FuncInfo] {
    if sigs, ok := localPackageFunctionSigs[path]; ok {
        if sig, ok := sigs[name]; ok {
            return base.Some[FuncInfo](sig.Prototype())
        }
    }
    return base.None[FuncInfo]()
}

func localPackageFuncSig(path string, name string, argCount int) base.Option[FuncInfo] {
    if sigs, ok := localPackageFunctionSigs[path]; ok {
        if sig, ok := sigs[name]; ok {
            if value, ok := sig.Exact(argCount); ok {
                return base.Some[FuncInfo](value)
            }
            return base.None[FuncInfo]()
        }
    }
    return base.None[FuncInfo]()
}

func localMethodNames(receiverType string) []string {
    if names, ok := localMethodNameMap[receiverType]; ok {
        return names
    }
    return []string{}
}

func localMethodPrototype(receiverType string, name string) base.Option[FuncInfo] {
    if sigs, ok := localMethodSigsByReceiver[receiverType]; ok {
        if sig, ok := sigs[name]; ok {
            return base.Some[FuncInfo](sig.Prototype())
        }
    }
    return base.None[FuncInfo]()
}

func localMethodSig(receiverType string, name string, argCount int) base.Option[FuncInfo] {
    if sigs, ok := localMethodSigsByReceiver[receiverType]; ok {
        if sig, ok := sigs[name]; ok {
            if value, ok := sig.Exact(argCount); ok {
                return base.Some[FuncInfo](value)
            }
            return base.None[FuncInfo]()
        }
    }
    return base.None[FuncInfo]()
}

func localStructFieldNames(typeName string) []string {
    if fields, ok := localStructFieldNamesMap[localNormalizeOwnerType(typeName)]; ok {
        return fields
    }
    return []string{}
}

func localStructFieldType(typeName string, fieldName string) string {
    if fields, ok := localStructFieldTypesMap[localNormalizeOwnerType(typeName)]; ok {
        if typ, ok := fields[fieldName]; ok {
            return typ
        }
    }
    return ""
}

func localInterfaceMethods(interfaceType string) []FuncInfo {
    if methods, ok := localInterfaceMethodsMap[localNormalizeOwnerType(interfaceType)]; ok {
        return methods
    }
    return []FuncInfo{}
}

func localNamedUnderlyingType(typeName string) string {
    if underlying, ok := localNamedUnderlyingTypes[localNormalizeOwnerType(typeName)]; ok {
        return underlying
    }
    return ""
}

func localKnownTypeNames() []string {
    return localKnownTypes
}

func localKnownTypeOwner(typeName string) string {
    return localKnownTypeOwners[localNormalizeOwnerType(typeName)]
}

func localNormalizeOwnerType(typeName string) string {
    for len(typeName) > 0 && typeName[0] == '*' {
        typeName = typeName[1:]
    }
    for idx := 0; idx < len(typeName); idx++ {
        if typeName[idx] == '[' {
            return typeName[:idx]
        }
    }
    return typeName
}

type localGeneratedFuncSig struct {
    Name             string
    FixedParamNames  []string
    FixedParamTypes  []string
    Variadic         bool
    VariadicName     string
    VariadicElemType string
    ResultTypes      []string
}

func (sig localGeneratedFuncSig) Prototype() FuncInfo {
    return FuncInfo{Name: sig.Name, TypeParams: []string{}, ParamNames: sig.FixedParamNames, ParamTypes: sig.FixedParamTypes, ResultTypes: sig.ResultTypes}
}

func (sig localGeneratedFuncSig) Exact(argCount int) (FuncInfo, bool) {
    if sig.Variadic {
        if argCount < len(sig.FixedParamTypes) {
            return FuncInfo{}, false
        }
        return VariadicFuncInfo(sig.Name, sig.FixedParamNames, sig.FixedParamTypes, sig.VariadicElemType, argCount, sig.ResultTypes), true
    }
    if argCount != len(sig.FixedParamTypes) {
        return FuncInfo{}, false
    }
    return sig.Prototype(), true
}
